import java.util.Arrays;

public static long solve(long[] nums) {
    if (nums == null || nums.length == 0) {
        return 0;
    }

    int n = nums.length;
    boolean[] isPrime = new boolean[n];
    Arrays.fill(isPrime, true);

    // Sieve of Eratosthenes to mark non-prime indices
    if (n >= 1) {
        isPrime[0] = false;
    }
    if (n >= 2) {
        isPrime[1] = false;
    }
    for (int i = 2; i * i < n; i++) {
        if (isPrime[i]) {
            for (int j = i * i; j < n; j += i) {
                isPrime[j] = false;
            }
        }
    }

    long sumA = 0;
    long sumB = 0;

    for (int i = 0; i < n; i++) {
        if (isPrime[i]) {
            sumA += nums[i];
        } else {
            sumB += nums[i];
        }
    }

    return Math.abs(sumA - sumB);
}
